import json
import re

# Read the full WiFi businesses data
file_path = locals()['var_functions.query_db:18']

# Load the data
with open(file_path, 'r') as f:
    all_businesses = json.load(f)

# Better filtering for actual WiFi availability
wifi_businesses = []
for business in all_businesses:
    attrs = business.get('attributes', {})
    if attrs and 'WiFi' in attrs:
        wifi_value = str(attrs['WiFi']).lower()
        # Include businesses with WiFi that is not 'no' or "u'no'"
        if 'no' not in wifi_value and 'false' not in wifi_value:
            # Extract state from description
            description = business.get('description', '')
            state_match = re.search(r',\s*([A-Z]{2})[.,\s]', description)
            if state_match:
                state = state_match.group(1)
                wifi_businesses.append({
                    'business_id': business['business_id'],
                    'state': state,
                    'wifi': attrs['WiFi']
                })

# Count per state
state_counts = {}
state_business_ids = {}
for b in wifi_businesses:
    state = b['state']
    state_counts[state] = state_counts.get(state, 0) + 1
    if state not in state_business_ids:
        state_business_ids[state] = []
    state_business_ids[state].append(b['business_id'])

# Find state with max businesses
if state_counts:
    max_state = max(state_counts, key=state_counts.get)
    max_count = state_counts[max_state]

    result = {
        'max_state': max_state,
        'max_count': max_count,
        'business_ids': state_business_ids[max_state],
        'total_wifi_businesses': len(wifi_businesses),
        'state_distribution': state_counts
    }
else:
    result = {'error': 'No data found'}

print('__RESULT__:')
print(json.dumps(result))

